diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
index fdef49e310f8..38ecb23f5516 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
@@ -819,12 +819,27 @@ Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
       return new ICmpInst(ICmpInst::ICMP_EQ, X, CmpC);
     }

+    if (match(Src, m_LShr(m_APInt(C1), m_Value(X)))) {
+      // trunc (lshr C, X) to i1 --> X == log2(C), where C is pow2
+      // trunc (lshr C, X) to i1 --> X ult log2(C+1), where C = 2^k-1
+      if (C1->isPowerOf2()) {
+        Constant *Log2C = ConstantInt::get(SrcTy, C1->exactLogBase2());
+        return new ICmpInst(ICmpInst::ICMP_EQ, X, Log2C);
+      }
+      APInt C1PlusOne = *C1 + 1;
+      if (C1PlusOne.isPowerOf2()) {
+        Constant *Log2CPlusOne = ConstantInt::get(SrcTy, C1PlusOne.exactLogBase2());
+        return new ICmpInst(ICmpInst::ICMP_ULT, X, Log2CPlusOne);
+      }
+    }
+
     if (match(Src, m_Shr(m_Value(X), m_SpecificInt(SrcWidth - 1)))) {
       // trunc (ashr X, BW-1) to i1 --> icmp slt X, 0
       // trunc (lshr X, BW-1) to i1 --> icmp slt X, 0
       return new ICmpInst(ICmpInst::ICMP_SLT, X, Zero);
     }

+
     Constant *C;
     if (match(Src, m_OneUse(m_LShr(m_Value(X), m_ImmConstant(C))))) {
       // trunc (lshr X, C) to i1 --> icmp ne (and X, C'), 0

